import React from 'react';
import { Routes, Route } from 'react-router-dom'; // 🚀 라우터 추가
import Header from './components/Header/Header';
import Main from './components/Main/Main';
import Footer from './components/Footer/Footer';
import Sub from './components/sub/Sub'; // 🚀 우리가 곧 만들 서브페이지!
import Cart from './components/Cart/Cart';
import Login from './components/Login/Login';
import Event from './components/EVENT/event';
import BucketClub from './components/BUCKETS_CLUB/bucket_club';
import Outlet from './components/OUTLET/outlet';
import ThanksArchive from './components/THANKS_ARCHIVE/thanks_archive';
import Search from './components/Search/Search';

function App() {
  return (
    <div>
      <Header />
      
      {/* 🚀 화면 가운데 알맹이만 주소에 따라 바뀝니다 */}
      <Routes>
        <Route path="/" element={<Main />} />            {/* 기본 화면은 Main */}
        <Route path="/sub/:id" element={<Sub />} />      {/* 상품 누르면 Sub 띄우기 */}
        <Route path="/cart" element={<Cart />} />
        <Route path="/login" element={<Login />} />
        <Route path="/event" element={<Event />} />
        <Route path="/bucket-club" element={<BucketClub />} />
        <Route path="/outlet" element={<Outlet />} />
        <Route path="/archive" element={<ThanksArchive />} />
        <Route path="/search" element={<Search />} />
      </Routes>

      <Footer />
    </div>
  );
}

export default App;