import React, { useEffect } from 'react';
import './thanks_archive.css';

function ThanksArchive() {
  // 페이지 진입 시 맨 위로 스크롤
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  return (
    <div className="archive_container">
      
      {/* 🚀 경로 표시 (Breadcrumb) 부분 */}
      <div className="breadcrumb">
        <span>Home</span> {'>'} <strong>THANKS, ARCHIVE</strong>
      </div>

      {/* 📸 땡스 아카이브 메인 배너 이미지 */}
      <div className="archive_img_wrap">
        {/* 🚀 수정완료: 교안 추천 방식 적용! (중괄호로 묶고 기계 이름 더하기) */}
        <img src={process.env.PUBLIC_URL + '/img/thanks_archive/thanks_archive1.jpg'} alt="THANKS ARCHIVE" />
      </div>

    </div>
  );
}

export default ThanksArchive;