import React from 'react';
import ReactDoM from 'react-dom/client';
import './index.css';
import App from './App';
import { BrowserRouter } from 'react-router-dom'; // 🚀 1. 라우터 대장님 수입!

// 🚨🚨🚨 [추가 1] 리덕스 도구 2개 가져오기! 🚨🚨🚨
import { Provider } from 'react-redux';
import store from './store/store';

const root = ReactDoM.createRoot(document.getElementById('root'));
root.render(
  // 🚨🚨🚨 [추가 2] Provider로 샌드위치처럼 위아래를 감싸주기! 🚨🚨🚨
  <Provider store={store}> 
    <BrowserRouter basename='/shop5'>
      <App/>
    </BrowserRouter>
  </Provider>
);