import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useDispatch } from "react-redux";
import { addToCart } from "../../store/cartSlice";
import { Swiper, SwiperSlide } from "swiper/react";
import { Pagination } from "swiper/modules";
import "swiper/css";
import "swiper/css/pagination";
import "./Sub.css";

function Sub() {
  const { id } = useParams();
  const navigate = useNavigate();
  const dispatch = useDispatch();

  const [product, setProduct] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [selectedSize, setSelectedSize] = useState("");
  const [tap, setTap] = useState(0);
  const [fade, setFade] = useState("");
  const [reviewSort, setReviewSort] = useState("추천순");
  const [photoOnly, setPhotoOnly] = useState(false);

  const [reviews, setReviews] = useState([
    {
      id: 1,
      author: "김**",
      date: "2026.04.07",
      rating: 5,
      text: "핏이 너무 예쁘고 재질도 좋습니다! 만족해요.",
      options: "SIZE: S",
      helpful: 12,
    },
    {
      id: 2,
      author: "이**",
      date: "2026.04.06",
      rating: 4,
      text: "사이즈 딱 맞네요. 배송도 빠릅니다. 색상도 화면과 같아요.",
      options: "SIZE: M",
      helpful: 5,
    },
    {
      id: 3,
      author: "박**",
      date: "2026.04.01",
      rating: 5,
      text: "선물했는데 너무 맘에 들어하네요! 최고입니다.",
      options: "SIZE: L",
      helpful: 24,
    },
  ]);

  const [reviewInput, setReviewInput] = useState("");
  const [reviewNameInput, setReviewNameInput] = useState("");
  const [reviewSizeInput, setReviewSizeInput] = useState("");
  const [reviewRating, setReviewRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);

  // 🚀 수정 모드 관련 state
  const [editingId, setEditingId] = useState(null);
  const [editText, setEditText] = useState("");
  const [editRating, setEditRating] = useState(0);
  const [editHoverRating, setEditHoverRating] = useState(0);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
    import(`../../data/product/detail_${id}.json`)
      .then((data) => setProduct(data.default || data))
      .catch((err) => console.log("데이터를 찾을 수 없습니다!", err));
  }, [id]);

  useEffect(() => {
    let timer = setTimeout(() => {
      setFade("end");
    }, 100);
    return () => {
      clearTimeout(timer);
      setFade("");
    };
  }, [tap]);

  if (!product)
    return <div className="loading_msg">상품 정보를 불러오는 중입니다...</div>;

  const priceNum = parseInt(product.price.replace(/,/g, ""));
  const totalPrice = (priceNum * quantity).toLocaleString();

  // 🚀 리뷰 통계 동적 계산
  const totalReviews = reviews.length;
  const avgRating =
    totalReviews > 0
      ? (reviews.reduce((sum, r) => sum + r.rating, 0) / totalReviews).toFixed(
          1,
        )
      : "0.0";
  const ratingCounts = [5, 4, 3, 2, 1].map((star) => ({
    star,
    count: reviews.filter((r) => r.rating === star).length,
    percent:
      totalReviews > 0
        ? Math.round(
            (reviews.filter((r) => r.rating === star).length / totalReviews) *
              100,
          )
        : 0,
  }));

  const handleAddToCart = () => {
    if (!selectedSize) {
      alert("옵션 선택은 필수입니다!");
      return;
    }
    const newItem = {
      cartId: Date.now(),
      productId: product.id,
      code: product.code || `M-CODE-${product.id}`,
      img:
        (product.sliderImages && product.sliderImages[0]) ||
        "https://via.placeholder.com/500",
      name: product.name,
      size: selectedSize,
      quantity: quantity,
      price: priceNum,
    };
    dispatch(addToCart(newItem));
    alert("상품이 장바구니에 추가되었습니다!");
  };

  const handleReviewSubmit = () => {
    if (!reviewNameInput || !reviewInput)
      return alert("이름과 리뷰 내용을 모두 입력해주세요!");
    if (!reviewSizeInput) return alert("구매하신 사이즈를 선택해주세요!");
    if (!reviewRating) return alert("별점을 선택해주세요!");

    const newReview = {
      id: Date.now(),
      author: reviewNameInput,
      date: new Date().toLocaleDateString(),
      rating: reviewRating,
      text: reviewInput,
      options: `SIZE: ${reviewSizeInput}`,
      helpful: 0,
    };
    setReviews([newReview, ...reviews]);
    setReviewInput("");
    setReviewNameInput("");
    setReviewSizeInput("");
    setReviewRating(0);
    setHoverRating(0);
  };

  const handleReviewDelete = (reviewId) => {
    if (window.confirm("정말 삭제하시겠습니까?")) {
      setReviews(reviews.filter((rev) => rev.id !== reviewId));
    }
  };

  // 🚀 수정 시작
  const handleEditStart = (rev) => {
    setEditingId(rev.id);
    setEditText(rev.text);
    setEditRating(rev.rating);
    setEditHoverRating(0);
  };

  // 🚀 수정 취소
  const handleEditCancel = () => {
    setEditingId(null);
    setEditText("");
    setEditRating(0);
    setEditHoverRating(0);
  };

  // 🚀 수정 저장
  const handleEditSave = (reviewId) => {
    if (!editText.trim()) return alert("리뷰 내용을 입력해주세요!");
    if (!editRating) return alert("별점을 선택해주세요!");
    setReviews(
      reviews.map((rev) =>
        rev.id === reviewId
          ? { ...rev, text: editText, rating: editRating }
          : rev,
      ),
    );
    handleEditCancel();
  };

  // 정렬
  const sortedReviews = [...reviews].sort((a, b) => {
    if (reviewSort === "추천순") return b.helpful - a.helpful;
    if (reviewSort === "별점순") return b.rating - a.rating;
    if (reviewSort === "최신순") return new Date(b.date) - new Date(a.date);
    return 0;
  });

  return (
    <div className="sub_container">
      <br></br>
      <div className="sub_top">
        <div className="sub_left">
          <Swiper
            modules={[Pagination]}
            pagination={{ clickable: true }}
            className="sub_image_slider"
          >
            <SwiperSlide>
              <img
                src={
                  product.sliderImages && product.sliderImages[0]
                    ? process.env.PUBLIC_URL + product.sliderImages[0]
                    : "https://via.placeholder.com/500"
                }
                alt={product.name}
              />
            </SwiperSlide>
            <SwiperSlide>
              <img
                src={
                  product.sliderImages && product.sliderImages[1]
                    ? process.env.PUBLIC_URL + product.sliderImages[1]
                    : "https://via.placeholder.com/500"
                }
                alt={`${product.name} 2`}
              />
            </SwiperSlide>
          </Swiper>
        </div>

        <div className="sub_info">
          <h2 className="sub_title">{product.name}</h2>
          <p className="sub_price">
            <strong>{product.price}</strong>원
          </p>
          <hr className="sub_line" />
          <ul className="sub_benefits">
            <li>
              <strong>배송정보</strong> 30,000원 이상 결제 시 무료배송
            </li>
            <li>
              <strong>카드혜택</strong> 신용카드 무이자 할부 안내
            </li>
          </ul>
          <hr className="sub_line" />

          <div className="option_group">
            <span className="option_label">COLOR</span>
            <div className="color_chip">
              <img
                src={
                  product.colorImage
                    ? process.env.PUBLIC_URL + product.colorImage
                    : "https://via.placeholder.com/40"
                }
                alt="color"
              />
            </div>
          </div>
          <div className="option_group option_select_group">
            <span className="option_label">SIZE</span>
            <select
              className="size_select"
              value={selectedSize}
              onChange={(e) => setSelectedSize(e.target.value)}
            >
              <option value="" disabled>
                - 옵션 선택 -
              </option>
              <option value="S">S</option>
              <option value="M">M</option>
              <option value="L">L</option>
            </select>
          </div>
          <hr className="sub_line" />
          <div className="sub_quantity">
            <span>
              {product.name} {selectedSize ? `- ${selectedSize}` : ""}
            </span>
            <div className="qty_box">
              <button onClick={() => setQuantity((q) => Math.max(1, q - 1))}>
                -
              </button>
              <span>{quantity}</span>
              <button onClick={() => setQuantity((q) => q + 1)}>+</button>
            </div>
          </div>

          <div className="sub_total">
            <span>총 상품금액</span>
            <strong>{totalPrice}원</strong>
          </div>

          <div className="sub_btns">
            <button className="btn_wish">♡</button>
            <button className="btn_buy" onClick={handleAddToCart}>
              BUY IT NOW
            </button>
            <button className="btn_cart" onClick={() => navigate("/cart")}>
              CART
            </button>
          </div>
        </div>
      </div>

      <div className="sub_bottom">
        <div className="tab_menu">
          <div className={tap === 0 ? "active" : ""} onClick={() => setTap(0)}>
            상세정보
          </div>
          <div className={tap === 1 ? "active" : ""} onClick={() => setTap(1)}>
            상품후기 ({reviews.length})
          </div>
          <div className={tap === 2 ? "active" : ""} onClick={() => setTap(2)}>
            배송/교환/반품
          </div>
        </div>

        <div className={`tab_content start ${fade}`}>
          {
            [
              // 탭 0: 상세정보
              <div className="tab_detail_imgs" key="tab_0">
                {product.detailImages &&
                  product.detailImages.map((imgUrl, i) => (
                    <img
                      key={i}
                      src={process.env.PUBLIC_URL + imgUrl}
                      alt={`상세 ${i}`}
                    />
                  ))}
              </div>,

              // 탭 1: 상품후기
              <div className="tab_reviews" key="tab_1">
                <div className="review_summary_box">
                  <div className="summary_score">
                    <h2>{avgRating}</h2>
                    <p className="stars">
                      {"★".repeat(Math.round(avgRating))}
                      {"☆".repeat(5 - Math.round(avgRating))}
                    </p>
                    <p className="total_count">전체 리뷰수 {totalReviews}</p>
                  </div>
                  <div className="summary_bars">
                    {ratingCounts.map(({ star, percent }) => (
                      <div className="bar_row" key={star}>
                        <span>{star}점</span>
                        <div className="bar_track">
                          <div
                            className="bar_fill"
                            style={{ width: `${percent}%` }}
                          ></div>
                        </div>
                        <span>{percent}%</span>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="review_filter_bar">
                  <div className="filter_left">
                    {["추천순", "최신순", "별점순"].map((sort) => (
                      <button
                        key={sort}
                        className={reviewSort === sort ? "active" : ""}
                        onClick={() => setReviewSort(sort)}
                      >
                        {sort}
                      </button>
                    ))}
                  </div>
                  <div className="filter_right">
                    <label>
                      <input
                        type="checkbox"
                        checked={photoOnly}
                        onChange={() => setPhotoOnly(!photoOnly)}
                      />{" "}
                      포토/동영상 먼저 보기
                    </label>
                    <div className="search_box">
                      <input type="text" placeholder="리뷰 키워드 검색" />
                      <button>🔍</button>
                    </div>
                  </div>
                </div>

                <div className="review_list">
                  {sortedReviews.map((rev) => (
                    <div key={rev.id} className="review_item">
                      <div className="review_item_left">
                        <div className="user_profile">👤</div>
                      </div>
                      <div className="review_item_right">
                        <div className="review_info_header">
                          <div className="review_info">
                            {/* 수정 모드일 때 별점 클릭 가능하게 */}
                            {editingId === rev.id ? (
                              <div className="edit_star_input">
                                {[1, 2, 3, 4, 5].map((star) => (
                                  <span
                                    key={star}
                                    className={`star_btn ${star <= (editHoverRating || editRating) ? "active" : ""}`}
                                    onClick={() => setEditRating(star)}
                                    onMouseEnter={() =>
                                      setEditHoverRating(star)
                                    }
                                    onMouseLeave={() => setEditHoverRating(0)}
                                  >
                                    ★
                                  </span>
                                ))}
                              </div>
                            ) : (
                              <span className="stars">
                                {"★".repeat(rev.rating)}
                                {"☆".repeat(5 - rev.rating)}
                              </span>
                            )}
                            <span className="author">{rev.author}</span>
                            <span className="date">{rev.date}</span>
                          </div>

                          {/* 🚀 수정/삭제/저장/취소 버튼 */}
                          <div className="review_action_btns">
                            {editingId === rev.id ? (
                              <>
                                <button
                                  className="btn_edit_save"
                                  onClick={() => handleEditSave(rev.id)}
                                >
                                  저장
                                </button>
                                <button
                                  className="btn_edit_cancel"
                                  onClick={handleEditCancel}
                                >
                                  취소
                                </button>
                              </>
                            ) : (
                              <>
                                <button
                                  className="btn_edit"
                                  onClick={() => handleEditStart(rev)}
                                >
                                  수정
                                </button>
                                <button
                                  className="btn_delete"
                                  onClick={() => handleReviewDelete(rev.id)}
                                >
                                  삭제
                                </button>
                              </>
                            )}
                          </div>
                        </div>

                        <p className="review_options">[옵션] {rev.options}</p>

                        {/* 수정 모드일 때 textarea로 전환 */}
                        {editingId === rev.id ? (
                          <textarea
                            className="edit_textarea"
                            value={editText}
                            onChange={(e) => setEditText(e.target.value)}
                          />
                        ) : (
                          <p className="review_text">{rev.text}</p>
                        )}

                        <button className="btn_helpful">
                          👍 도움이 돼요 {rev.helpful}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="review_write">
                  <div className="review_write_header">
                    <div className="review_input_group">
                      <span className="label">이름</span>
                      <input
                        type="text"
                        placeholder="작성자 이름"
                        value={reviewNameInput}
                        onChange={(e) => setReviewNameInput(e.target.value)}
                      />
                    </div>
                    <div className="review_input_group">
                      <span className="label">사이즈</span>
                      <select
                        value={reviewSizeInput}
                        onChange={(e) => setReviewSizeInput(e.target.value)}
                      >
                        <option value="" disabled>
                          - 사이즈 선택 -
                        </option>
                        <option value="S">S</option>
                        <option value="M">M</option>
                        <option value="L">L</option>
                      </select>
                    </div>
                    <div className="review_input_group">
                      <span className="label">별점</span>
                      <div className="star_input">
                        {[1, 2, 3, 4, 5].map((star) => (
                          <span
                            key={star}
                            className={`star_btn ${star <= (hoverRating || reviewRating) ? "active" : ""}`}
                            onClick={() => setReviewRating(star)}
                            onMouseEnter={() => setHoverRating(star)}
                            onMouseLeave={() => setHoverRating(0)}
                          >
                            ★
                          </span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <textarea
                    placeholder="상품후기를 작성해주세요."
                    value={reviewInput}
                    onChange={(e) => setReviewInput(e.target.value)}
                  />
                  <button
                    className="btn_review_submit"
                    onClick={handleReviewSubmit}
                  >
                    등록
                  </button>
                </div>
              </div>,

              // 탭 2: 배송/교환/반품 안내
              <div className="tab_delivery" key="tab_2">
                <h4>배송 및 교환/반품 안내 (요약)</h4>
                <ul className="delivery_list">
                  <li>
                    <strong>- 배송 준비:</strong> 주문 확인 후 출고까지{" "}
                    <strong>1~2일</strong> 소요됩니다.
                  </li>
                  <li>
                    <strong>- 배송 기간:</strong> 출고 후 평균{" "}
                    <strong>3~5일</strong> 소요됩니다. (주말/공휴일 제외)
                  </li>
                  <li>
                    <strong>- 제주·도서산간:</strong> 추가 배송비가 발생할 수
                    있습니다.
                  </li>
                  <li>
                    <strong>- 교환/반품 신청:</strong> 상품 수령 후{" "}
                    <strong>7일 이내</strong> 가능합니다.
                  </li>
                  <li>
                    <strong>- 단순 변심:</strong> 왕복 배송비가 부과됩니다.
                  </li>
                  <li>
                    <strong>- 불량 상품:</strong> 확인 후 무상 교환/반품
                    진행됩니다.
                  </li>
                  <li>
                    <strong>- 교환/반품 불가:</strong> 착용/사용 흔적, 택 제거,
                    상품 훼손 시 불가합니다.
                  </li>
                </ul>
                <p className="delivery_notice">
                  ※ 자세한 내용은 <strong>상세페이지 하단 배송정보</strong>를 꼭
                  확인해 주세요.
                </p>
              </div>,
            ][tap]
          }
        </div>
      </div>
    </div>
  );
}

export default Sub;
