import React from 'react';
import { useNavigate } from 'react-router-dom'; // 🚀 1. Link 대신 useNavigate 가져오기!
import './Footer.css';

function Footer() {
  const navigate = useNavigate(); // 🚀 2. 이동 기능 세팅

  // 🚀 3. 메인 이동 + 스무스 스크롤 마법 함수!
  const handleGoHome = () => {
    navigate('/'); // 메인으로 먼저 이동
    setTimeout(() => {
      window.scrollTo({ top: 0, behavior: 'smooth' }); // 0.05초 뒤 스무스하게 샥!
    }, 50);
  };

  return (
    <footer>
      <div className="footer_inner">

        {/* 왼쪽 */}
        <div className="footer_left">
          <h1 className="footer_logo">
            {/* 🚀 4. Link 대신 span으로 감싸고 마법 함수 연결! (마우스 손가락 모양도 유지) */}
            <span onClick={handleGoHome} style={{ cursor: 'pointer' }}>
              {/* 🚀 수정완료: 교안 추천 방식 적용! (중괄호로 묶고 기계 이름 더하기) */}
              <img src={process.env.PUBLIC_URL + '/img/icon/top_logo.png'} alt="malbon golf" />
            </span>
          </h1>
          <ul className="footer_menu">
            <li>회사소개</li>
            <li>이용안내</li>
            <li className="point">개인정보처리방침</li>
            <li>이용약관</li>
            <li>구매안전(에스크로)서비스</li>
          </ul>
          <ul></ul>
          <div className="footer_info">
            <p>상호명 : 주식회사 하이라이트브랜즈 | 호스팅 제공자 : (주)위사</p>
            <p>말본골프 | malbon golf | 대표이사 : Jun Kwon Lee | 주소 : 경기 성남시 분당구 판교로 242 PDC빌딩 A동 8F</p>
            <p>통신판매업신고 : 2019-성남분당B-0523 | 사업자등록번호 : 788-81-01239 | 개인정보보호책임자 : 고상현</p>
            <p>문의 이메일 : minhee.jung@hibs.co.kr | 고객센터 : 031-8060-0290</p>
          </div>
          <div className="footer_copy">
            <p>Copyright by 말본골프 | malbon golf. all rights reserved.</p>
            <p>The Malbon golf's trademark, logo and other rights are solely used by</p>
            <p>Modern Works under license from Malbon golf. Hilight Brands is a division within Modern Works.</p>
          </div>
        </div>

        {/* 오른쪽 */}
        <div className="footer_right">
          <ul className="footer_link1">
            <li>NOTICE</li>
            <li>REVIEW</li>
            <li>매장안내</li>
          </ul>
          <ul className="footer_link2">
            <li>마이페이지</li>
            <li>주문배송조회</li>
            <li>위시리스트</li>
            <li>1:1 문의하기</li>
          </ul>
          <ul className="footer_link3">
            <li>Facebook</li>
            <li>Instagram</li>
          </ul>
        </div>

      </div>
    </footer>
  );
}

export default Footer;