import React, { useState, useEffect } from 'react'; // 🚀 useState 추가!
import './event.css';
import eventData from '../../data/event/event.json';

function Event() {
  // 🚀 검색을 위한 상태 저장소 만들기
  const [searchType, setSearchType] = useState('제목');
  const [searchKeyword, setSearchKeyword] = useState('');

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  return (
    <div className="event_container">
      <h2 className="event_title_main">EVENT</h2>

      <div className="event_grid">
        {eventData.map((item) => (
          <div className="event_item" key={item.id}>
            <div className="event_img_box">
              {/* 🚀 수정완료 1: 보관함 사진 (따옴표 없이 기계 이름 넣기) */}
              <img src={process.env.PUBLIC_URL + item.img} alt={item.title} />
            </div>
            <div className="event_info">
              <span className="event_brand">{item.brand}</span>
              <span className="event_desc">{item.title}  {item.desc}</span>
            </div>
          </div>
        ))}
      </div>

      {/* 🚨🚨🚨 새로 추가된 하단 영역 (페이지네이션 + 검색창) 🚨🚨🚨 */}
      <div className="event_bottom_area">
        
        {/* 1. 네모난 페이지네이션 */}
        <div className="pagination">
          <span className="page_num active">1</span>
          <span className="page_num">2</span>
          <span className="page_num">3</span>
        </div>

        {/* 2. 드롭다운이 포함된 검색창 */}
        <div className="event_search_box">
          <select 
            className="search_select" 
            value={searchType}
            onChange={(e) => setSearchType(e.target.value)}
          >
            <option value="제목">제목</option>
            <option value="내용">내용</option>
            <option value="작성자">작성자</option>
          </select>
          
          <input 
            type="text" 
            className="search_input" 
            value={searchKeyword}
            onChange={(e) => setSearchKeyword(e.target.value)}
          />
          
          <button className="search_btn">
            {/* 🚀 수정완료 2: 직접 쓴 사진 (중괄호로 묶고 더하기) */}
            <img src={process.env.PUBLIC_URL + '/img/event/search_btn.png'} alt="검색" />
          </button>
        </div>

      </div>
    </div>
  );
}

export default Event;