import React, { useState } from "react"; // 🚀 1. useState 추가!
import { Link, useNavigate } from "react-router-dom"; // 🚀 2. useNavigate 추가!
import "./Header.css";

function Header() {
  const navigate = useNavigate(); // 🚀 3. 이동 기능 켜기
  const [searchTerm, setSearchTerm] = useState(""); // 🚀 4. 검색어 보관함 만들기

  // 🚀 5. 검색창에서 엔터 치거나 돋보기 누를 때 실행되는 함수!
  const handleSearch = (e) => {
    e.preventDefault(); // 엔터 쳤을 때 새로고침 되는 걸 막아줍니다
    if (searchTerm.trim() !== "") {
      navigate(`/search?q=${searchTerm}`); // 검색 페이지로 검색어 달고 슉! 이동
    }
  };

  return (
    <header>
      {/* 상단 초록 배너 */}
      <div className="header_top">
        <p>구매 금액별 사은품 혜택</p>
      </div>

      {/* 메인 헤더 */}
      <div className="header_middle">
        <div className="header_inner">
          <h1 className="header_logo">
            <Link to="/">
              {/* 🚀 수정완료 1: 로고 이미지 */}
              <img
                src={process.env.PUBLIC_URL + "/img/icon/top_logo.png"}
                alt="malbon golf"
              />
            </Link>
          </h1>

          {/* 🚨🚨 여기가 핵심입니다! 🚨🚨 
              기존 div 껍데기를 form(진짜 입력 양식)으로 바꾸고 onSubmit을 달아줬습니다. */}
          <form className="header_search" onSubmit={handleSearch}>
            <input
              type="text"
              placeholder="검색어를 입력해주세요 (말본,티셔츠,팬츠..)"
              value={searchTerm}
              onChange={(e) =>
                setSearchTerm(e.target.value)
              } /* 글자 칠 때마다 보관함에 저장 */
            />
            <button type="submit">
              {/* 🚀 수정완료 2: 돋보기 이미지 */}
              <img
                src={process.env.PUBLIC_URL + "/img/icon/search_btn.png"}
                alt="검색"
              />
            </button>
          </form>

          <div className="header_util">
            {/* 1. 로그인 (기존 그대로) */}
            <Link
              to="/login"
              style={{ textDecoration: "none", color: "inherit" }}
            >
              <span>로그인</span>
            </Link>

            {/* 🚀 2. 회원가입 클릭 시 로그인 페이지로 이동! */}
            <Link
              to="/login"
              style={{ textDecoration: "none", color: "inherit" }}
            >
              <span>회원가입</span>
            </Link>

            {/* 🚀 3. 마이페이지 클릭 시 장바구니 페이지로 이동! */}
            <Link
              to="/cart"
              style={{ textDecoration: "none", color: "inherit" }}
            >
              <span>마이페이지</span>
            </Link>

            {/* 4. 장바구니 (기존 그대로) */}
            <Link
              to="/cart"
              style={{ textDecoration: "none", color: "inherit" }}
            >
              <span className="cart">
                장바구니
                <strong className="cart_count">0</strong>
              </span>
            </Link>
          </div>
        </div>
      </div>

      {/* 네비게이션 */}
      <nav className="header_nav">
        <div className="header_inner relative_box">
          <ul className="nav_left">
            {/* 🚀 드롭다운 싹 지우고 다른 메뉴들과 똑같이 깔끔하게 맞췄습니다! */}
            <li>
              <Link
                to="/sub/20"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                NEW RELEASES
              </Link>
            </li>
            <li>
              <Link
                to="/sub/13"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                MEN
              </Link>
            </li>
            <li>
              <Link
                to="/sub/9"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                WOMEN
              </Link>
            </li>
            <li>
              <Link
                to="/sub/17"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                YOUTH
              </Link>
            </li>
            <li>
              <Link
                to="/sub/1"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                ACCESSORIES
              </Link>
            </li>
            <li>
              <Link
                to="/sub/2"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                EXCLUSIVE
              </Link>
            </li>
            <li>
              <Link
                to="/sub/3"
                style={{
                  textDecoration: "none",
                  color: "inherit",
                  display: "flex",
                  alignItems: "center",
                }}
              >
                {/* 🚀 수정완료 3: BLAZE 아이콘 이미지 */}
                <img
                  src={process.env.PUBLIC_URL + "/img/icon/gnb_img_menu.png"}
                  alt="blaze"
                />
                BLAZE
              </Link>
            </li>
          </ul>
          <ul className="nav_right">
            <li>
              <Link
                to="/outlet"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                OUTLET
              </Link>
            </li>
            <li>
              <Link
                to="/event"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                EVENT
              </Link>
            </li>
            <li>
              <Link
                to="/bucket-club"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                BUCKETS CLUB
              </Link>
            </li>
            <li>
              <Link
                to="/archive"
                style={{ textDecoration: "none", color: "inherit" }}
              >
                THANKS, ARCHIVE
              </Link>
            </li>
          </ul>
        </div>
      </nav>
    </header>
  );
}

export default Header;
