import React from 'react';
import './Login.css';

function Login() {
  return (
    <div className="login_container">
      
      {/* 1. 회원 로그인 영역 */}
      <div className="login_section">
        <h2 className="login_title">로그인</h2>
        
        <input type="text" className="login_input" placeholder="아이디" />
        <input type="password" className="login_input" placeholder="비밀번호" />
        
        <div className="login_options">
          <div className="option_left">
            <label><input type="checkbox" /> 보안접속</label>
            <label><input type="checkbox" /> 아이디저장</label>
          </div>
          <span className="find_link">아이디/비밀번호 찾기</span>
        </div>

        <button className="btn_black">로그인</button>

        {/* 🚀 노란색 펜으로 칠하셨던 SNS 아이콘 영역! */}
        <div className="sns_login_area">
          <p>SNS 계정으로 로그인하기</p>
          <div className="sns_icons">
            {/* 🚀 수정완료 1: 네이버 아이콘 */}
            <img src={process.env.PUBLIC_URL + '/img/login/ico_naver.png'} alt="네이버 로그인" />
            <span className="sns_line"></span> {/* 🚀 네이버와 카카오 사이에 구분선 추가! */}
            {/* 🚀 수정완료 2: 카카오톡 아이콘 */}
            <img src={process.env.PUBLIC_URL + '/img/login/ico_kakaotalk.png'} alt="카카오 로그인" />
          </div>
        </div>

        <div className="signup_area">
          <p>아직 회원이 아니신가요?</p>
          <button className="btn_white">회원가입</button>
        </div>
      </div>

      {/* 2. 비회원 주문조회 영역 */}
      <div className="guest_section">
        <h2 className="login_title">비회원 주문조회</h2>
        
        <input type="text" className="login_input" placeholder="주문번호" />
        <input type="text" className="login_input" placeholder="전화번호" />
        
        <div className="login_options">
          <div className="option_left">
            <label><input type="checkbox" defaultChecked /> 보안접속</label>
          </div>
        </div>

        <button className="btn_black">주문조회</button>
      </div>

    </div>
  );
}

export default Login;