import React, { useEffect } from 'react';
import './outlet.css';

function Outlet() {
  // 페이지 진입 시 맨 위로 스크롤
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  return (
    <div className="outlet_container">
      
      {/* 🚀 스샷에 노란색으로 동그라미 치신 경로 표시 (Breadcrumb) 부분! */}
      <div className="breadcrumb">
        <span>Home</span> {'>'} <strong>OUTLET</strong>
      </div>

      {/* 📸 아울렛 메인 배너 이미지 */}
      <div className="outlet_img_wrap">
        {/* 🚀 수정완료: 교안 추천 방식 적용! (중괄호로 묶고 기계 이름 더하기) */}
        <img src={process.env.PUBLIC_URL + '/img/outlet/outlet1.jpg'} alt="OUTLET Archive sale" />
      </div>

    </div>
  );
}

export default Outlet;