import React from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { increaseQty, decreaseQty, removeItem, sortByName } from '../../store/cartSlice';
import './Cart.css';

function Cart() {
  const cartItems = useSelector((state) => state.cart);
  const dispatch = useDispatch();

  // 🚀 핵심 포인트: 장바구니 총 금액 계산기!
  // cartItems(장바구니 배열)를 싹 돌면서 (상품 가격 * 수량)을 전부 더해줍니다.
  const totalPrice = cartItems.reduce((total, item) => {
    return total + (item.price * item.quantity);
  }, 0);

  return (
    <div className="cart_container">
      <h2 className="cart_title">쿼카의 장바구니</h2>
      <table className="cart_table">
        <thead>
          <tr>
            <th>상품코드</th>
            <th>상품이미지</th>
            <th>상품명</th>
            <th>수량</th>
            <th>가격</th> {/* 🚀 표 머리글에 '가격' 추가! */}
            <th>수량관리</th>
          </tr>
        </thead>
        <tbody>
          {cartItems.map(item => (
            <tr key={item.cartId}>
              <td>{item.code || 'M-CODE-000'}</td>
              
              <td className="cart_img_cell">
                <img src={process.env.PUBLIC_URL + item.img} alt={item.name} />
              </td>
              
              <td>{item.name} {item.size ? `[SIZE: ${item.size}]` : ''}</td>
              <td>{item.quantity}</td>
              
              {/* 🚀 각 상품의 (가격 * 수량)을 보여줍니다. toLocaleString()은 1,000단위 콤마(,)를 예쁘게 찍어주는 마법의 단어입니다! */}
              <td className="item_price">
                {(item.price * item.quantity).toLocaleString()}원
              </td>
              
              <td>
                <div className="cart_controls">
                  <button onClick={() => dispatch(increaseQty(item.cartId))}>+</button>
                  <button onClick={() => dispatch(decreaseQty(item.cartId))}>-</button>
                  <button className="btn_remove" onClick={() => dispatch(removeItem(item.cartId))}>상품삭제</button>
                </div>
              </td>
            </tr>
          ))}
          {cartItems.length === 0 && (
            <tr><td colSpan="6" className="empty_cart">장바구니가 비어있습니다.</td></tr>
          )}
        </tbody>
      </table>

      {/* 🚀 하단 버튼과 총합계 박스 영역 */}
      <div className="cart_bottom_area">
        <button className="btn_sort" onClick={() => dispatch(sortByName())}>이름순정렬</button>
        
        {/* 영근님이 스케치하신 TOTAL 박스 구현! */}
        <div className="cart_total_box">
          <span className="total_label">TOTAL :</span>
          <span className="total_price">{totalPrice.toLocaleString()} 원</span>
        </div>
      </div>
      
    </div>
  );
}

export default Cart;