import { Link } from 'react-router-dom';
import React, { useState } from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Navigation, Pagination, Autoplay } from 'swiper/modules';
import 'swiper/css';
import 'swiper/css/navigation';
import 'swiper/css/pagination';
import './Main.css';

// 🚀 데이터 임포트
import mainBannerData from '../../data/main/MAIN_BANNER.json'; 
import newInData from '../../data/main/NewIn.json';
import topSellerData from '../../data/main/TOP_SELLER.json';
import secondSliderData from '../../data/main/SECOND_SLIDER.json'; 
import spotlightData from '../../data/main/SPOTLIGHT_CODI.json'; 
import bestItemData from '../../data/main/BEST_ITEM.json';

function TopSellerCard({ item }) {
  const [isHover, setIsHover] = useState(false);
  return (
    <div
      className="top_card"
      onMouseEnter={() => setIsHover(true)}
      onMouseLeave={() => setIsHover(false)}
    >
      <div className="top_img">
        {/* 🚀 수정 1: 마우스 올리면 바뀌는 사진 (괄호로 묶고 기계 이름 더하기!) */}
        <img src={process.env.PUBLIC_URL + (isHover ? item.back : item.front)} alt={item.name} />
      </div>
      <div className="top_info">
        <p className="top_name">{item.name}</p>
        <p className="top_code">{item.code}</p>
        <p className="top_price">{item.price}</p>
      </div>
    </div>
  );
}

function Main() {
  const [hoveredId, setHoveredId] = useState(null);
  const [topSellers, setTopSellers] = useState(topSellerData);
  const [activeSort, setActiveSort] = useState('이름순');
  const [visibleBestItems, setVisibleBestItems] = useState(4);
  
  const handleMoreClick = () => {
    if (visibleBestItems >= bestItemData.length) {
      alert("더 이상 상품이 없습니다");
    } else {
      setVisibleBestItems(8); 
    }
  };

  const getPriceNumber = (priceStr) => {
    if (!priceStr) return 0;
    return Number(priceStr.replace(/[^0-9]/g, ""));
  };

  const handleSort = (type) => {
    setActiveSort(type);
    let sorted = [...topSellerData];
    if (type === '이름순') {
      sorted.sort((a, b) => a.name.localeCompare(b.name));
    } else if (type === '가격낮은순') {
      sorted.sort((a, b) => getPriceNumber(a.price) - getPriceNumber(b.price));
    } else if (type === '가격높은순') {
      sorted.sort((a, b) => getPriceNumber(b.price) - getPriceNumber(a.price));
    }
    setTopSellers(sorted);
  };

  return (
    <main>
      {/* 1. 메인 배너 슬라이더 */}
      <div className="main_banner">
        <Swiper
          modules={[Navigation, Pagination, Autoplay]}
          navigation={true}
          pagination={{ clickable: true }}
          autoplay={{ delay: 3000, disableOnInteraction: false }}
          loop={true}
        >
          {mainBannerData.map((item) => (
            <SwiperSlide key={item.id}>
              {/* 🚀 수정 2: 보관함 사진 */}
              <img src={process.env.PUBLIC_URL + item.img} alt={item.alt} />
            </SwiperSlide>
          ))}
        </Swiper>
      </div>

      {/* 2. NEW IN 섹션 */}
      <section className="newin_section">
        <div className="newin_header">
          <div className="newin_title">
            <h2>NEW IN</h2>
            <p>이번주, 새롭게 공개된 말본골프의 컬렉션을 지금 바로 확인하세요.</p>
          </div>
        </div>
        <div className="newin_slider">
          <Swiper
            modules={[Navigation]}
            navigation={true}
            slidesPerView={5}
            spaceBetween={10}
          >
            {newInData.map((item) => (
              <SwiperSlide key={item.id}>
                <Link to={`/sub/${item.id}`} style={{ textDecoration: 'none', color: 'inherit' }}>
                <div
                  className="newin_card"
                  onMouseEnter={() => setHoveredId(item.id)}
                  onMouseLeave={() => setHoveredId(null)}
                >
                  <div className="newin_img">
                    {/* 🚀 수정 3: 마우스 올리면 바뀌는 사진 (괄호로 묶고 기계 이름 더하기!) */}
                    <img
                      src={process.env.PUBLIC_URL + (hoveredId === item.id ? item.back : item.front)}
                      alt={item.name}
                    />
                  </div>
                  <div className="newin_info">
                    <p className="newin_name">{item.name}</p>
                    <p className="newin_code">{item.code}</p>
                    <p className="newin_price">{item.price}</p>
                  </div>
                </div>
                </Link>
              </SwiperSlide>
            ))}
          </Swiper>
        </div>
      </section>

      {/* 3. BRAND PROMOTION 섹션 */}
      <section className="brand_section">
        <div className="brand_header">
          <h2>BRAND PROMOTION</h2>
          <span>더 보러가기 &gt;</span>
        </div>
        <div className="brand_list">
          <div className="brand_item">
            {/* 🚀 수정 4: 직접 적힌 사진 주소 */}
            <img src={process.env.PUBLIC_URL + '/img/main/BRAND_PROMOTION/brand_outlet.jpg'} alt="outlet" />
          </div>
          <div className="brand_item">
            {/* 🚀 수정 5: 직접 적힌 사진 주소 */}
            <img src={process.env.PUBLIC_URL + '/img/main/BRAND_PROMOTION/brand_member.jpg'} alt="membership" />
          </div>
        </div>
      </section>

      {/* 4. TOP SELLER 섹션 */}
      <section className="top_seller_section">
       <div className="top_header">
        <div className="top_header_left">
          <h2>TOP SELLER</h2>
          <h3>지금 가장 인기있는</h3>
        </div>
        <div className="sort_menu">
          <span
            className={activeSort === '이름순' ? 'active' : ''}
            onClick={() => handleSort('이름순')}
          >이름순</span>
          <span className="divider">|</span>
          <span
            className={activeSort === '가격낮은순' ? 'active' : ''}
            onClick={() => handleSort('가격낮은순')}
          >가격낮은순</span>
          <span className="divider">|</span>
          <span
            className={activeSort === '가격높은순' ? 'active' : ''}
            onClick={() => handleSort('가격높은순')}
          >가격높은순</span>
        </div>
      </div>
        <div className="top_grid">
          {topSellers.map((item) => (
            <Link to={`/sub/${item.id}`} key={item.id} style={{ textDecoration: 'none', color: 'inherit' }}>
            <TopSellerCard key={item.id} item={item} />
            </Link>
          ))}
        </div>
      </section>

      {/* 5. 두 번째 배너 슬라이더 */}
      <section className="second_banner_section">
        <Swiper
          modules={[Pagination, Autoplay, Navigation]}
          navigation={true}
          pagination={{ clickable: true }}
          autoplay={{ delay: 3500, disableOnInteraction: false }}
          loop={true}
          className="second_banner_swiper"
        >
          {secondSliderData.map((item) => (
            <SwiperSlide key={item.id}>
              {/* 🚀 수정 6: 보관함 사진 */}
              <img src={process.env.PUBLIC_URL + item.img} alt={item.alt} />
            </SwiperSlide>
          ))}
        </Swiper>
      </section>

      {/* 6. SPOTLIGHT CODI 섹션 */}
      <section className="spotlight_section">
        <div className="spotlight_header">
          <h2>SPOTLIGHT CODI</h2>
          <h3>셋업으로 입어야 멋이나요!</h3>
        </div>
        
        <div className="spotlight_grid">
          {spotlightData.map((col) => (
            <div className="spotlight_col" key={col.id}>
              <div className="spotlight_main_img">
                {/* 🚀 수정 7: 보관함 사진 */}
                <img src={process.env.PUBLIC_URL + col.mainImg} alt={col.title} />
              </div>
              
              <div className="spotlight_content">
                <h4 className="spotlight_col_title">{col.title}</h4>
                <p className="spotlight_col_desc">{col.desc}</p>
                
                <div className="spotlight_items">
                  {col.items.map((item) => (
                    <div className="spotlight_item" key={item.id}>
                      <div className="spotlight_thumb">
                        {/* 🚀 수정 8: 썸네일 보관함 사진 */}
                        <img src={process.env.PUBLIC_URL + item.thumb} alt={item.name} />
                      </div>
                      <div className="spotlight_item_info">
                        <p className="spotlight_item_name">{item.name}</p>
                        <p className="spotlight_item_code">{item.code}</p>
                        <p className="spotlight_item_price">{item.price}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* 7. BEST ITEM 섹션 */}
      <section className="best_item_section">
        <div className="best_header">
          <div className="best_header_title">
            <h2>BEST ITEM</h2>
            <h3>지금 말본골프의 인기있는 상품들을 만나보세요.</h3>
          </div>
          
          <button 
            className="btn_best_more" 
            onClick={handleMoreClick} 
          >
            상품 더보기
          </button>
        </div>

        <div className="best_grid">
          {bestItemData.slice(0, visibleBestItems).map((item) => (
            <div className="best_card" key={item.id}>
              <div className="best_img">
                {/* 🚀 수정 9: 보관함 사진 */}
                <img src={process.env.PUBLIC_URL + item.img} alt={item.name} />
              </div>
              <div className="best_info">
                <p className="best_name">{item.name}</p>
                <p className="best_code">{item.code}</p>
                <p className="best_price">{item.price}</p>
              </div>
            </div>
          ))}
        </div>
      </section>
    </main>
  );
}

export default Main;