import React, { useState, useEffect } from "react";
import { useSearchParams, useNavigate, Link } from "react-router-dom";
import "./Search.css";

function Search() {
  const [searchParams] = useSearchParams();
  const query = searchParams.get("q") || ""; // 주소창에서 검색어 빼오기
  const navigate = useNavigate();

  const [localQuery, setLocalQuery] = useState(query); // 페이지 가운데 대왕 검색창용
  const [allProducts, setAllProducts] = useState([]); // 1~20번 모든 상품
  const [filteredProducts, setFilteredProducts] = useState([]); // 검색 결과
  const [sortType, setSortType] = useState("이름순"); // 정렬 상태

  // 1. 페이지 열릴 때 1~20번 JSON 데이터 싹 다 불러오기
  useEffect(() => {
    const loadProducts = async () => {
      let loaded = [];
      for (let i = 1; i <= 20; i++) {
        try {
          const data = await import(`../../data/product/detail_${i}.json`);
          loaded.push(data.default || data);
        } catch (err) {
          // 데이터가 없으면 무시
        }
      }
      setAllProducts(loaded);
    };
    loadProducts();
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, []);

  // 2. 검색어가 바뀌거나, 정렬 버튼을 누를 때마다 리스트 업데이트!
  useEffect(() => {
    setLocalQuery(query); // 쿼리가 바뀌면 가운데 검색창 글씨도 업데이트

    // 검색어가 포함된 상품만 필터링
    let result = allProducts.filter((p) => p.name.includes(query));

    // 영근님이 요청하신 정렬 로직! 🚀
    if (sortType === "이름순") {
      result.sort((a, b) => a.name.localeCompare(b.name));
    } else if (sortType === "가격낮은순") {
      result.sort(
        (a, b) =>
          parseInt(a.price.replace(/,/g, "")) -
          parseInt(b.price.replace(/,/g, "")),
      );
    } else if (sortType === "가격높은순") {
      result.sort(
        (a, b) =>
          parseInt(b.price.replace(/,/g, "")) -
          parseInt(a.price.replace(/,/g, "")),
      );
    }

    setFilteredProducts(result);
  }, [query, allProducts, sortType]);

  // 대왕 검색창에서 검색했을 때
  const handleBigSearch = (e) => {
    e.preventDefault();
    if (localQuery.trim()) navigate(`/search?q=${localQuery}`);
  };

  return (
    // 🚀 영근님이 좋아하시는 스무스 애니메이션도 달아드렸습니다!
    <div className="search_page_container page_fade_in" key={query}>
      {/* 상단 타이틀 & 대왕 검색창 */}
      <h2 className="search_main_title">상품검색</h2>
      <form className="big_search_box" onSubmit={handleBigSearch}>
        <input
          type="text"
          value={localQuery}
          onChange={(e) => setLocalQuery(e.target.value)}
          placeholder="검색어를 입력해주세요"
        />
        <button type="submit">
          <img
            src={process.env.PUBLIC_URL + "/img/icon/search_btn.png"}
            alt="검색"
          />
        </button>
      </form>

      {/* 중간 필터 바 (검색결과 수 + 정렬 버튼) */}
      <div className="search_filter_bar">
        <div className="filter_left">
          검색어 <strong>'{query}'</strong>에 대한 결과가{" "}
          <strong>{filteredProducts.length}</strong>개 있습니다.
        </div>

        {/* 🚀 스샷에 그려주신 동글동글 정렬 버튼! */}
        <div className="filter_right">
          {["이름순", "가격낮은순", "가격높은순"].map((type, idx) => (
            <React.Fragment key={type}>
              <button
                className={`sort_pill ${sortType === type ? "active" : ""}`}
                onClick={() => setSortType(type)}
              >
                {type}
              </button>
              {idx !== 2 && <span className="sort_divider">|</span>}
            </React.Fragment>
          ))}
        </div>
      </div>

      {/* 상품 그리드 영역 */}
      <div className="search_product_grid">
        {filteredProducts.length > 0 ? (
          filteredProducts.map((p) => (
            <div className="search_product_card" key={p.id}>
              {/* 🚀 바로 이 부분입니다! 클릭하면 '/sub/상품번호' 로 이동하게 Link를 걸어줬어요! 🚀 */}
              <Link
                to={`/sub/${p.id}`}
                style={{ textDecoration: "none", color: "inherit" }}
              >
                <div className="img_wrap">
                  {/* 슬라이드 이미지가 있으면 첫 번째 거, 없으면 메인 이미지 */}
                  <img
                    src={
                      process.env.PUBLIC_URL +
                      ((p.sliderImages && p.sliderImages[0]) || p.img)
                    }
                    alt={p.name}
                  />
                </div>
                <div className="prod_info">
                  <p className="prod_name">{p.name}</p>
                  <p className="prod_code">{p.code || `M-CODE-00${p.id}`}</p>
                  <p className="prod_price">
                    <strong>{p.price}</strong>원
                  </p>
                </div>
              </Link>
              {/* 🚀 Link 끝! */}
            </div>
          ))
        ) : (
          <div className="no_result">
            <p>검색 결과가 없습니다. 😭</p>
          </div>
        )}
      </div>
    </div> // (제일 바깥쪽 container 닫는 괄호)
  );
}

export default Search;
