import React, { useState, useEffect } from 'react';
import './bucket_club.css';

function BucketClub() {
  // 🚀 검색창 상태 관리
  const [searchType, setSearchType] = useState('제목');
  const [searchKeyword, setSearchKeyword] = useState('');

  // 페이지 진입 시 맨 위로 스크롤
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  return (
    <div className="bucket_container">
      <h2 className="bucket_title_main">BUCKETS CLUB</h2>

      {/* 📸 사진 콘텐츠 영역 (하드코딩으로 깔끔하게!) */}
      <div className="bucket_content">
        {/* 1. 첫 번째 긴 메인 이미지 */}
        <div className="bucket_img_wrap">
          {/* 🚀 수정완료: 교안 추천 방식 적용! */}
          <img src={process.env.PUBLIC_URL + '/img/bucket_club/bucket_club1_1.jpg'} alt="Buckets Club Main" />
        </div>

        {/* 2. 두 번째 사각형 포스터 이미지 (사우스 스프링스) */}
        <div className="bucket_img_wrap">
          {/* 🚀 수정완료: 교안 추천 방식 적용! */}
          <img src={process.env.PUBLIC_URL + '/img/bucket_club/bucket_club1_2.jpg'} alt="South Springs Country Club" />
          
          {/* 🚀 방금 추가한 하단 텍스트 영역! */}
          <div className="bucket_text_area">
            <h3 className="bucket_item_title">Malbon Golf</h3>
            <p className="bucket_item_desc">버킷클럽 - 사우스 스프링스 컨트리 클럽 (26년 4월 30일)</p>
            <p className="bucket_item_date">2026.03.09 ~ 2026.03.25</p>
          </div>
        </div>
      </div>

      {/* 🔍 하단 페이지네이션 & 검색창 영역 (이벤트 페이지와 동일) */}
      <div className="bucket_bottom_area">
        
        <div className="pagination">
          {/* 게시물이 적으니 1페이지만 활성화해둡니다 */}
          <span className="page_num active">1</span>
        </div>

        <div className="bucket_search_box">
          <select 
            className="search_select" 
            value={searchType}
            onChange={(e) => setSearchType(e.target.value)}
          >
            <option value="제목">제목</option>
            <option value="내용">내용</option>
            <option value="작성자">작성자</option>
          </select>
          
          <input 
            type="text" 
            className="search_input" 
            value={searchKeyword}
            onChange={(e) => setSearchKeyword(e.target.value)}
          />
          
          <button className="search_btn">
            {/* 🚀 수정완료: 돋보기 이미지도 교안 추천 방식으로! */}
            <img src={process.env.PUBLIC_URL + '/img/bucket_club/search_btn.png'} alt="검색" />
          </button>
        </div>

      </div>
    </div>
  );
}

export default BucketClub;